def unify_explanation(subsystem_name, raw_explanation):
    if subsystem_name == "forecaster":
        return {
            "recommendation": raw_explanation["model_choice"],
            "supporting_quantities": {"mae_vs_baseline": raw_explanation["mae_improvement"]},
            "alternatives_considered": raw_explanation["candidates"],
            "confidence_statement": raw_explanation["limitations"],
        }
    elif subsystem_name == "battery_scheduler":
        return {
            "recommendation": raw_explanation["recommended_action"],
            "supporting_quantities": {
                "cost": raw_explanation["estimated_cost_impact"],
                "emissions": raw_explanation["estimated_emissions_impact"],
            },
            "alternatives_considered": raw_explanation.get("candidate_actions", []),
            "confidence_statement": raw_explanation["rationale"],
        }
